import getUnavailableCategories from "../api/getUnavailableCategories";
import deleteUnavailableCategory from "../api/deleteUnavailableCategory";
import deleteAllUnavailableProducts from "../api/deleteAllUnavailableProducts";
import addUnavailableCategory from "../api/addUnavailableCategory";
import toggleRemoveAllButton from "./toggleRemoveAllButton";
import showAlert from "./showAlert";
import handlePagination from "./handlePagination";

let pagination = null;

export default async function loadUnavailableCategories(
  page = 1,
  paginationHandler = null
) {
  const tableBody = document.querySelector(
    ".unavailable__table--unavailable tbody"
  );
  const removeAllButton = document.querySelector(".unavailable__remove-all");
  const searchInput = document.querySelector(".unavailable__search-main");
  const totalItemsEl = document.querySelector(
    "#unavailable-pagination .unavailable__pagination-total-items"
  );

  if (!tableBody || !removeAllButton) {
    return Promise.resolve();
  }

  if (!pagination) {
    pagination = handlePagination(loadUnavailableCategories);
  }

  removeAllButton.replaceWith(removeAllButton.cloneNode(true));
  const newRemoveAllButton = document.querySelector(".unavailable__remove-all");

  const loaderHTML = `
    <tr>
      <td colspan="4" style="text-align: center">
        <div class="unavailable__loader">
          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 200 200" style="height: 40px;">
            <radialGradient id="loader-gradient-unavailable" cx=".66" fx=".66" cy=".3125" fy=".3125" gradientTransform="scale(1.5)">
              <stop offset="0" stop-color="#0085BA"/>
              <stop offset=".3" stop-color="#0085BA" stop-opacity=".9"/>
              <stop offset=".6" stop-color="#0085BA" stop-opacity=".6"/>
              <stop offset=".8" stop-color="#0085BA" stop-opacity=".3"/>
              <stop offset="1" stop-color="#0085BA" stop-opacity="0"/>
            </radialGradient>
            <circle transform-origin="center" fill="none" stroke="url(#loader-gradient-unavailable)" stroke-width="15" stroke-linecap="round" stroke-dasharray="200 1000" stroke-dashoffset="0" cx="100" cy="100" r="70">
              <animateTransform type="rotate" attributeName="transform" calcMode="spline" dur="2" values="360;0" keyTimes="0;1" keySplines="0 0 1 1" repeatCount="indefinite"/>
            </circle>
            <circle transform-origin="center" fill="none" opacity=".2" stroke="#0085BA" stroke-width="15" stroke-linecap="round" cx="100" cy="100" r="70"/>
          </svg>
        </div>
      </td>
    </tr>
  `;

  tableBody.innerHTML = loaderHTML;

  try {
    const searchValue = searchInput?.value || "";
    const categoriesData = await getUnavailableCategories(searchValue, page);

    const { categories, total_categories, current_page, total_pages } =
      categoriesData;

    pagination.updatePaginationState({
      current_page,
      total_pages,
      total_products: total_categories,
    });

    if (totalItemsEl) {
      totalItemsEl.textContent = total_categories;
    }

    toggleRemoveAllButton(
      categories?.some(
        (category) => category.delivery_type !== null && category.delivery_type !== ""
      )
    );

    const courierText = document.querySelector(".unavailable-wrapper")?.dataset
      ?.courierText;
    const parcelLockerText = document.querySelector(".unavailable-wrapper")
      ?.dataset?.parcelLockerText;
    const noResultsMessage = document.querySelector(".unavailable-wrapper")
      ?.dataset?.noResultsMessage;

    if (!categories?.length) {
      tableBody.innerHTML = `
        <tr>
          <td colspan="4" style="text-align: center;">
            ${noResultsMessage}
          </td>
        </tr>
      `;
      return Promise.resolve();
    }

    const itemsPerPage = categories.length;
    const startIndex = (current_page - 1) * itemsPerPage;

    tableBody.innerHTML = categories
      .map(
        (category, index) => `
        <tr data-category-id="${category.id}">
          <td class="unavailable__td unavailable__td--count">${
            startIndex + index + 1
          }.</td>
          <td class="unavailable__td unavailable__td--product-name">
            ${category.title}
          </td>
          <td class="unavailable__td unavailable__td--id">${
            category.category_id
          }</td>
          <td class="unavailable__td unavailable__td--actions">
            <div class="unavailable__checkbox-wrapper">
              <input type="checkbox" class="unavailable__checkbox unavailable__checkbox--courier" data-category-id="${
                category.category_id
              }" ${
          category.delivery_type === "2" || category.delivery_type === "3"
            ? "checked"
            : ""
        } />
              <label class="unavailable__checkbox-label">
                  ${courierText}
              </label>
            </div>
            <div class="unavailable__checkbox-wrapper">
              <input type="checkbox" class="unavailable__checkbox unavailable__checkbox--parcel-locker" data-category-id="${
                category.category_id
              }" ${
          category.delivery_type === "1" || category.delivery_type === "3"
            ? "checked"
            : ""
        } />
              <label class="unavailable__checkbox-label">
                  ${parcelLockerText}
              </label>
            </div>
          </td>
        </tr>
      `
      )
      .join("");

    const handler = paginationHandler || window.unavailablePaginationHandler;

    if (handler) {
      handler.reinitialize();
    }

    setupEventListeners(tableBody, newRemoveAllButton);

    return Promise.resolve();
  } catch (error) {
    if (error.message === "Request cancelled") {
      return Promise.resolve();
    }

    console.error("Error loading unavailable categories:", error);
    showAlert(error);
    toggleRemoveAllButton(false);
    tableBody.innerHTML = `
      <tr>
        <td colspan="4" style="text-align: center; color: var(--unavailable-red);">
          ${
            document.querySelector(".unavailable-wrapper")?.dataset
              ?.apiErrorMessage
          }
        </td>
      </tr>
    `;
    pagination.reset();
    return Promise.reject(error);
  }
}

function setupEventListeners(tableBody, newRemoveAllButton) {
  tableBody.querySelectorAll(".unavailable__checkbox").forEach((checkbox) => {
    checkbox.addEventListener("change", async (e) => {
      const row = e.target.closest("tr");
      const courierCheckbox = row.querySelector(
        ".unavailable__checkbox--courier"
      );
      const parcelLockerCheckbox = row.querySelector(
        ".unavailable__checkbox--parcel-locker"
      );

      const isCourierChecked = courierCheckbox.checked;
      const isParcelLockerChecked = parcelLockerCheckbox.checked;

      try {
        row.classList.add("removing");
        if (!isCourierChecked && !isParcelLockerChecked) {
          await deleteUnavailableCategory(row.dataset.categoryId);
        } else {
          let deliveryType;
          if (isCourierChecked && isParcelLockerChecked) {
            deliveryType = "3";
          } else if (isCourierChecked) {
            deliveryType = "2";
          } else if (isParcelLockerChecked) {
            deliveryType = "1";
          }

          await addUnavailableCategory([
            {
              id: row.querySelector(".unavailable__td--id").textContent,
              delivery_type: deliveryType,
            },
          ]);
        }
      } catch (error) {
        console.error("Error updating product delivery type:", error);
        showAlert(error);
        e.target.checked = !e.target.checked;
      } finally {
        row.classList.remove("removing");
      }
    });
  });

  newRemoveAllButton.addEventListener("click", async () => {
    try {
      const rows = tableBody.querySelectorAll("tr");
      rows.forEach((row) => row.classList.add("removing"));

      await deleteAllUnavailableProducts();

      setTimeout(() => {
        loadUnavailableCategories(1);
        newRemoveAllButton.style.display = "none";
      }, 300);
    } catch (error) {
      showAlert(error);
      console.error("Error removing all products:", error);
      rows.forEach((row) => row.classList.remove("removing"));
    }
  });
}
