import showModal from "./unavailable-categories/modal/showModal";
import hideModals from "./unavailable-categories/modal/hideModals";
import loadSearchs from "./unavailable-categories/modal/loadSearchs";
import clearSearchs from "./unavailable-categories/modal/clearSearchs";
import resetCategoriesSearch from "./unavailable-categories/modal/resetCategoriesSearch";
import loadUnavailableCategories from "./unavailable-categories/modal/loadUnavailableCategories";
import resetSelectedProducts from "./unavailable-categories/modal/resetSelectedProducts";
import handleConfirmationModal from "./unavailable-categories/modal/handleConfirmationModal";

window.addEventListener("load", function () {
  const productsWrapper = document.querySelector(".unavailable-wrapper");

  if (!productsWrapper) {
    return;
  }

  loadUnavailableCategories().then(() => {
    setTimeout(() => {
      loadSearchs();
    }, 100);
  });

  const popupTable = productsWrapper?.querySelector(".unavailable-popup-table");
  const overlay = productsWrapper?.querySelector(".overlay");
  const selectProductsButton = productsWrapper?.querySelector(
    ".unavailable-select-products"
  );
  const closePopupButton = popupTable?.querySelector(
    ".unavailable__popup-close"
  );
  const cancelButton = productsWrapper?.querySelector(
    ".unavailable__table-actions-categories-btn"
  );

  const closeElements = [closePopupButton, cancelButton, overlay];

  closeElements.forEach((element) => {
    element &&
      element.addEventListener("click", () => {
        hideModals();
        resetCategoriesSearch();
        clearSearchs();
      });
  });

  selectProductsButton?.addEventListener("click", () => {
    showModal(popupTable, overlay);
    resetCategoriesSearch();
    clearSearchs();
    resetSelectedProducts();
  });

  handleConfirmationModal();
});
